using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Server;
using Microsoft.AspNetCore.Components.Web;

namespace sv_9ac502075be24fb9976e0a922328f1f1.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that creates a hardcoded authenticated user
/// and persists the claims via PersistentComponentState so the WebAssembly runtime
/// can restore the identity after it takes over.
/// </summary>
public sealed class PersistingAuthenticationStateProvider
    : ServerAuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private PersistingComponentStateSubscription _subscription;
    private Task<AuthenticationState>? _authStateTask;

    public PersistingAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;

        AuthenticationStateChanged += OnAuthenticationStateChanged;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);

        // Set the hardcoded user as the current authentication state.
        var claims = new[]
        {
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        };

        var identity = new ClaimsIdentity(claims, authenticationType: "Hardcoded");
        var user = new ClaimsPrincipal(identity);
        SetAuthenticationState(Task.FromResult(new AuthenticationState(user)));
    }

    private void OnAuthenticationStateChanged(Task<AuthenticationState> task)
    {
        _authStateTask = task;
    }

    private async Task OnPersistingAsync()
    {
        var authState = _authStateTask ?? Task.FromResult(await GetAuthenticationStateAsync());
        var principal = (await authState).User;

        if (principal.Identity?.IsAuthenticated == true)
        {
            _persistentState.PersistAsJson("UserClaims",
                principal.Claims.Select(c => new ClaimDto(c.Type, c.Value)).ToArray());
        }
    }

    public void Dispose()
    {
        _subscription.Dispose();
        AuthenticationStateChanged -= OnAuthenticationStateChanged;
    }

    /// <summary>Serialisable DTO used to persist claims across render modes.</summary>
    public sealed record ClaimDto(string Type, string Value);
}

using System.Security.Claims;
